# Category: oauth_security

from flask import Flask, request, jsonify
from flask_oauthlib.provider import OAuth2Provider

app = Flask(__name__)

oauth = OAuth2Provider(app)

auth_codes = {}

@oauth.token_request_handler
def token_request():
    code = request.form.get('code')
    user_id = auth_codes.get(code)
    if user_id:
        return jsonify({'access_token': user_id}), 200
    return jsonify({'error': 'invalid_grant'}), 400

@oauth.authorize_request_handler
def authorize_request():
    client_id = request.form.get('client_id')
    redirect_uri = request.form.get('redirect_uri')
    user_id = request.form.get('user_id')
    if client_id and redirect_uri and user_id:
        code = str(len(auth_codes))
        auth_codes[code] = user_id
        return jsonify({'code': code}), 200
    return jsonify({'error': 'invalid_request'}), 400

if __name__ == '__main__':
    app.run()